import React from 'react';
import { Link } from 'react-router-dom';
import { ShoppingCart, Trash2, Plus, Minus, ShoppingBag } from 'lucide-react';
import { useCart } from '../context/CartContext';

export default function CartPage() {
  const { cart, removeFromCart, updateQty, total, clearCart } = useCart();

  if (cart.length === 0) return (
    <div className="min-h-screen bg-[#0a0a0f] pt-20 flex flex-col items-center justify-center gap-6">
      <ShoppingBag size={64} className="text-gray-700" />
      <h2 className="text-white font-bold text-2xl">Your cart is empty</h2>
      <p className="text-gray-400">Browse our store and add items to cart</p>
      <Link to="/store" className="btn-fire">Go to Store</Link>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0a0a0f] pt-20">
      <div className="max-w-5xl mx-auto px-6 py-10">
        <div className="flex items-center justify-between mb-8">
          <h1 className="text-white font-bold text-3xl flex items-center gap-3"><ShoppingCart size={28} className="text-orange-500" /> Shopping Cart</h1>
          <button onClick={clearCart} className="text-red-400 text-sm hover:underline">Clear all</button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Items */}
          <div className="lg:col-span-2 space-y-4">
            {cart.map((item, i) => (
              <div key={i} className="glass rounded-xl p-4 flex items-center gap-4">
                {item.images?.[0] ? (
                  <img src={item.images[0]} alt={item.name} className="w-20 h-20 object-cover rounded-lg flex-shrink-0" />
                ) : (
                  <div className="w-20 h-20 bg-gray-800 rounded-lg flex items-center justify-center flex-shrink-0">
                    <ShoppingBag size={28} className="text-gray-600" />
                  </div>
                )}
                <div className="flex-1 min-w-0">
                  <h3 className="text-white font-semibold line-clamp-1">{item.name}</h3>
                  {(item.flavor || item.weight) && (
                    <p className="text-gray-500 text-xs">{[item.flavor, item.weight].filter(Boolean).join(' · ')}</p>
                  )}
                  <p className="text-orange-400 font-bold mt-1">₹{item.discountPrice || item.price}</p>
                </div>
                <div className="flex items-center gap-2 border border-white/10 rounded-lg">
                  <button onClick={() => updateQty(item._id, item.flavor, item.weight, item.qty - 1)} className="p-2 text-gray-400 hover:text-white"><Minus size={14} /></button>
                  <span className="text-white font-bold px-2 min-w-[24px] text-center">{item.qty}</span>
                  <button onClick={() => updateQty(item._id, item.flavor, item.weight, item.qty + 1)} className="p-2 text-gray-400 hover:text-white"><Plus size={14} /></button>
                </div>
                <div className="text-white font-bold min-w-[70px] text-right">₹{((item.discountPrice || item.price) * item.qty).toFixed(0)}</div>
                <button onClick={() => removeFromCart(item._id, item.flavor, item.weight)} className="text-red-400 hover:text-red-300 ml-2"><Trash2 size={18} /></button>
              </div>
            ))}
          </div>

          {/* Summary */}
          <div>
            <div className="glass rounded-xl p-6">
              <h2 className="text-white font-bold text-xl mb-6">Order Summary</h2>
              <div className="space-y-3 mb-6">
                {cart.map((item, i) => (
                  <div key={i} className="flex justify-between text-gray-400 text-sm">
                    <span className="line-clamp-1 flex-1 mr-2">{item.name} × {item.qty}</span>
                    <span>₹{((item.discountPrice || item.price) * item.qty).toFixed(0)}</span>
                  </div>
                ))}
                <div className="border-t border-white/10 pt-3 flex justify-between text-white font-bold text-lg">
                  <span>Total</span>
                  <span className="gradient-text">₹{total.toFixed(0)}</span>
                </div>
              </div>
              <Link to="/checkout" className="btn-fire w-full block text-center py-3">Proceed to Checkout</Link>
              <Link to="/store" className="block text-center text-gray-400 hover:text-orange-400 text-sm mt-4 transition-colors">← Continue Shopping</Link>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
